export const getUpdatePayrollLineUrl = (employeeId: number) => {
  return `/api/payroll/${employeeId}`;
};

export const updatePayrollLine = async (
  employeeId: number,
  updatePayrollLineBody: UpdatePayrollLineBody,
  options?: RequestInit,
): Promise<PayrollLine> => {
  return customFetch<PayrollLine>(getUpdatePayrollLineUrl(employeeId), {
    ...options,
    method: "PUT",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(updatePayrollLineBody),
  });
};

export const getUpdatePayrollLineMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updatePayrollLine>>,
    TError,
    { employeeId: number; data: BodyType<UpdatePayrollLineBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof updatePayrollLine>>,
  TError,
  { employeeId: number; data: BodyType<UpdatePayrollLineBody> },
  TContext
> => {
  const mutationKey = ["updatePayrollLine"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof updatePayrollLine>>,
    { employeeId: number; data: BodyType<UpdatePayrollLineBody> }
  > = (props) => {
    const { employeeId, data } = props ?? {};

    return updatePayrollLine(employeeId, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type UpdatePayrollLineMutationResult = NonNullable<
  Awaited<ReturnType<typeof updatePayrollLine>>
>;
export type UpdatePayrollLineMutationBody = BodyType<UpdatePayrollLineBody>;
export type UpdatePayrollLineMutationError = ErrorType<unknown>;

export const useUpdatePayrollLine = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updatePayrollLine>>,
    TError,
    { employeeId: number; data: BodyType<UpdatePayrollLineBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof updatePayrollLine>>,
  TError,
  { employeeId: number; data: BodyType<UpdatePayrollLineBody> },
  TContext
> => {
  return useMutation(getUpdatePayrollLineMutationOptions(options));
};

